BEGIN;

ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name,path=EXCLUDED.path;

ON CONFLICT (id) DO UPDATE SET email=EXCLUDED.email,password_hash=EXCLUDED.password_hash,first_name=EXCLUDED.first_name,
last_name=EXCLUDED.last_name,position=EXCLUDED.position,department_id=EXCLUDED.department_id,manager_id=EXCLUDED.manager_id,is_active=true;


ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name,description=EXCLUDED.description,category=EXCLUDED.category,is_active=true;

SELECT c.id,l.level,CASE l.level WHEN 1 THEN 'Базовый' WHEN 2 THEN 'Рабочий' WHEN 3 THEN 'Продвинутый' ELSE 'Экспертный' END,
'Демонстрирует компетенцию на соответствующем уровне'
FROM competencies c CROSS JOIN generate_series(1,4) AS l(level)
WHERE c.id::text LIKE 'c1000000-%' ON CONFLICT DO NOTHING;

ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name;

ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name;

ON CONFLICT (id) DO UPDATE SET title=EXCLUDED.title,goals=EXCLUDED.goals,start_date=EXCLUDED.start_date,end_date=EXCLUDED.end_date,
status=EXCLUDED.status,cancel_reason=EXCLUDED.cancel_reason,archived_at=NULL,updated_at=NOW();

ON CONFLICT (idp_id,competency_id) DO UPDATE SET current_level=EXCLUDED.current_level,target_level=EXCLUDED.target_level;

ON CONFLICT (id) DO UPDATE SET title=EXCLUDED.title,description=EXCLUDED.description,category_id=EXCLUDED.category_id,
priority=EXCLUDED.priority,due_date=EXCLUDED.due_date,status=EXCLUDED.status,progress=EXCLUDED.progress,
manager_rating=EXCLUDED.manager_rating,manager_comment=EXCLUDED.manager_comment,deleted_at=NULL,updated_at=NOW();



ON CONFLICT (id) DO UPDATE SET title=EXCLUDED.title,url=EXCLUDED.url;

ON CONFLICT (id) DO UPDATE SET content=EXCLUDED.content,is_deleted=false,created_at=EXCLUDED.created_at,updated_at=EXCLUDED.updated_at;

ON CONFLICT (id) DO UPDATE SET old_value=EXCLUDED.old_value,new_value=EXCLUDED.new_value,created_at=EXCLUDED.created_at;

ON CONFLICT (id) DO UPDATE SET title=EXCLUDED.title,description=EXCLUDED.description,goals=EXCLUDED.goals,target_role=EXCLUDED.target_role,is_active=true,updated_at=NOW();

DELETE FROM template_tasks WHERE template_id IN ('80000000-0000-0000-0000-000000000001','80000000-0000-0000-0000-000000000002','80000000-0000-0000-0000-000000000003');
DELETE FROM template_competencies WHERE template_id IN ('80000000-0000-0000-0000-000000000001','80000000-0000-0000-0000-000000000002','80000000-0000-0000-0000-000000000003');

ON CONFLICT (template_id,competency_id) DO UPDATE SET target_level=EXCLUDED.target_level;

COMMIT;
